class Solution {
public:
    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        vector<vector<double>> dp(n + 1, vector<double>(m, 1e18));
        dp[0][0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < m; j++) {
                dp[i][j] = min(dp[i][j], dp[i - 1][(j + 1) % m] + time[i - 1] * mul[j]);
                if (i - 1 >= k) {
                    dp[i][j] = min(dp[i][j], dp[i - k][(j + 1) % m] + max(time[i - k], time[i - 1]) * mul[j]);
                }
            }
        }
        double ans = 1e18;
        for (int i = 0; i < m; i++) {
            ans = min(ans, dp[n][i]);
        }
        return ans == 1e18 ? -1 : ans;
    }
};
